import machine
import ubinascii
from umqtt.simple import MQTTClient

# ESP32 Pin Definitions
DHTPIN = 4
DATA_PIN = 5

def read_temp_raw():
    dht.measure()
    temperature = dht.temperature()
    return temperature

dht = machine.Pin(DHTPIN)
dht.init(machine.Pin.IN, machine.Pin.PULL_UP)

# MQTT Broker Settings
BROKER_ADDRESS = "your_broker_ip"
CLIENT_ID = ubinascii.hexlify(machine.unique_id())
MQTT_PORT = 1883

def mqtt_callback(topic, msg):
    print('Received from {}: {}'.format(topic, str(msg)))

def on_connect(client):
    client.subscribe("sensors/temp")

def publish_temp():
    client = MQTTClient(CLIENT_ID, BROKER_ADDRESS, user='your_username', password='your_password')
    client.set_callback(mqtt_callback)
    client.connect()
    on_connect(client)

    while True:
        temperature = read_temp_raw()
        if not temperature is None:
            client.publish("sensors/temp", str(temperature))
            print('Published temperature: ', str(temperature))
        client.wait_puback()

# Start the main loop of publishing sensor data to MQTT Broker
publish_temp()